import{restUrl,postJson,getCookie,setCookie,deleteCookie,uuid,Modal,Toast,Theme}from"jui";import{createStorage}from"vanilla-create-storage";import{t as ts}from"vanilla-signal-i18n";const{success:success,error:error,warning:warning}=Toast;new Theme;const langs={en:{lwq:"Login via WeChat QrCode",fgq:"Failed to get QrCode"},zh:{lwq:"微信扫码登录",fgq:"获取二维码失败"}},t=e=>ts(e,langs),api=e=>restUrl+"/api/v1/auth/wechat/subscribe"+e;let currentPollingTimer=null;const m=new Modal({text:{title:t("lwq")},footer:!1,escClose:!0,content:'<div id="login-qrcode" style="text-align:center;min-height:280px"></div>',onHidden:()=>{m.state.loading=!1,stopPolling()}}),subscribeCookie="g3_wechat_login_hash",stopPolling=()=>{currentPollingTimer&&(clearTimeout(currentPollingTimer),currentPollingTimer=null)};for(const e of document.querySelectorAll("[data-login-element]"))e.addEventListener("click",e=>{e.preventDefault(),m.show(),m.state.loading=!0;const o=document.querySelector("#login-qrcode"),i=async()=>{let e=getCookie(subscribeCookie);if(!e)try{e=uuid(),setCookie(subscribeCookie,e,1800)}catch(e){return void error(e.message)}try{const i=await postJson(api("/qrcode"),{hash:`login:${e}`});if(200!==i.code||!i.data||!i.data.url)throw new Error(i.message||t("fgq"));setTimeout(()=>{m.state.loading=!1,o.innerHTML=`<img src="${i.data.url}" alt="${t("lwq")}" style="width:280px; height:auto; outline:1px solid var(--ui-border)" />`},800),setTimeout(()=>{s(e)},2e3)}catch(e){error(e.message)}},s=e=>{stopPolling();const t=3e3,o=async()=>{try{const i=await postJson(api("/validate"),{hash:`login:${e}`});if(!0===i.success)success(i.message),deleteCookie(subscribeCookie),stopPolling(),setTimeout(()=>{window.location.href="/"},1e3);else{if(i.status&&"expired"===i.status)return warning(i.message),deleteCookie(subscribeCookie),void stopPolling();currentPollingTimer=setTimeout(o,t)}}catch{currentPollingTimer=setTimeout(o,2*t)}};o()};i()});